        } else {
            // Query type 2: update nums[idx] to val
            const idx = query[1];
            const val = query[2];
            nums[idx] = val;
            const oldDepth = popcountDepth[idx];
            const newDepth = countSetBits(val);
            popcountDepth[idx] = newDepth;
            updateDepthFreq(idx, oldDepth, newDepth);
        }
    }

    return answer;
